L8CC5:
    LDY #$34
    SEI
    STY $01
    LDY #$00
L8CCC:
    INC $1D
    BNE L8CD2
    INC $1E
L8CD2:
    LDA ($1D),Y
    BNE L8CCC
    LDY #$36
    STY $01
    CLI
    RTS
L8CDC:
    .byte $0E  ; $8CDC .
    .byte $CD, $4F, $44, $45, $4D, $20, $46, $41, $55, $4C, $54, $0D, $00  ; $8CDD .ODEM FAULT..
L8CEA:
    .byte $93  ; $8CEA .
    .byte $0E, $08, $11, $C9, $4E, $50, $55, $54, $20, $50, $48, $4F, $4E, $45, $20, $4E  ; $8CEB ....NPUT PHONE N
    .byte $55, $4D, $42, $45, $52, $00  ; $8CFB UMBER.
L8D01:
    .byte $20  ; $8D01  
    .byte $4F, $52, $20, $D2, $C5, $D4, $D5, $D2, $CE, $2E, $00  ; $8D02 OR ........
L8D0D:
    .byte $0D  ; $8D0D .
    .byte $11, $CE, $55, $4D, $42, $45, $52, $3F, $20, $20, $00  ; $8D0E ..UMBER?  .
L8D19:
    .byte $11  ; $8D19 .
    .byte $C4, $49, $41, $4C, $4C, $49, $4E, $47, $20, $00  ; $8D1A .IALLING .
L8D24:
    .byte $50  ; $8D24 P
    .byte $4C, $45, $41, $53, $45, $20, $57, $41, $49, $54, $00  ; $8D25 LEASE WAIT.

; --- MODEM_CHECK ---
; ;--- MODIFIED: skip brick modem check, go straight to phone input ---
MODEM_CHECK:
    TSX
    STX $C154
    JMP L8D52
L8D52:
    JSR L9050
    LDA $8013
    STA VIC_BGCOL0
    LDA $8014
    STA $0286
    LDX #.lobyte(L8CEA)
    LDY #.hibyte(L8CEA)
    JSR PRINT_STRING                    ; PRINT_STRING
    LDY #$01
    LDA L9FF0
    BEQ L8D78
    LDX #$01                            ; SETUP_INPUT_PARAMS
    LDY #$8D
    JSR PRINT_STRING
    LDY #$00                            ; PRINT_STRING
L8D78:
    LDX #$10
    LDA #$2D
    SEC
    JSR SETUP_INPUT_PARAMS              ; INPUT_LINE
    LDX #.lobyte(L8D0D)
    LDY #.hibyte(L8D0D)
    JSR PRINT_STRING
    LDX #$00
    LDY #$02
    JSR INPUT_LINE
    BCC L8D91
    RTS
L8D91:
    JSR L906E
    LDX $1A
    BEQ L8DA4
    STX L9FF0
L8D9B:
    LDA $01FF,X
    STA L9FF0,X
    DEX
    BNE L8D9B
L8DA4:
    LDX #.lobyte(L8D19)
    LDY #.hibyte(L8D19)
    JSR PRINT_STRING                    ; Print "DIALLING"
    ; ;--- MODIFIED: Init ACIA here (after phone input, before dial) ---
    JSR ACIA_INIT
    ; Hayes AT dial via ACIA driver
    JSR ACIA_DIAL
    BCS L8E1C                           ; C=1 = failed
    JSR ACIA_PROTO_CONNECT              ; Polling-based handshake (replaces L96D5)
    BCC L8E1F                           ; C=0 = success
L8E1C:
    JMP PROTO_DISPATCH_TABLE
L8E1F:
    LDX #.lobyte(L8D24)
    LDY #.hibyte(L8D24)                            ; PROTO_DISPATCH_TABLE
    JSR PRINT_STATUS_MSG
    CLC
    ROR $C155
    ; ;--- MODIFIED: Skip PROTO_FLOW_CONTROL — server has nothing to send yet ---
    JMP L8E35
L8E35:
    JSR L9050
L8E38:
    LDX #.lobyte(L9507)
    LDY #.hibyte(L9507)
    JSR L89E2
    LDA #$02
    STA $0286
    LDA #$5A
    STA $C100
    LDX #$10
    LDY #$12
    CLC
    JSR $FFF0
    LDX #$08                            ; INPUT_LINE
    LDY #$01
    LDA #$00
    CLC
    JSR SETUP_INPUT_PARAMS
    LDX #$01
    LDY #$C1
    JSR INPUT_LINE
    BCS L8E38
    LDY $1A
    LDA #$20
L8E68:
    STA $C101,Y
    INY
    CPY #$08
    BCC L8E68                           ; KERNAL_CHROUT
    LDX #$12
    LDY #$0D
    CLC
    JSR $FFF0
    LDX #$00
L8E7A:
    LDA #$5F
    JSR KERNAL_CHROUT
    LDA #$9D
    JSR KERNAL_CHROUT
    JSR CLEAR_STATUS
    CMP #$0D
    BEQ L8EA3
    CPX #$06
    BEQ L8E7A
    STA $C109,X                         ; KERNAL_CHROUT
    CMP #$30
    BCC L8E7A
    CMP #$5B
    BCS L8E7A
    INX
    LDA #$2A
    JSR KERNAL_CHROUT
    JMP L8E7A
L8EA3:
    JSR L906A
    LDA #$20
L8EA8:
    STA $C109,X
    INX
    CPX #$06
    BCC L8EA8
    LDX #$37
    STX $01
    LDX #$09
L8EB6:
    LDA $8039,X
    STA $C10F,X
    DEX
    BPL L8EB6
    LDX #$36
    STX $01
    LDA $A000
    STA $C119
    LDA $A001
    STA $C11A
    LDX #$24                            ; MODEM_REG_WRITE_WAIT
    LDY #$8D
    JSR PRINT_STATUS_MSG
    LDA #$43
    STA $8034
    LDY #$1B
    JSR MODEM_REG_WRITE_WAIT
    JSR L96D2
    BCC L8EE8
    JMP L8E38
L8EE8:
    JSR L89D0
    SEC
    ROR $C155

; --- MODEM_INIT_DOWNLOAD ---
; Receive terminal software during LINKING phase
MODEM_INIT_DOWNLOAD:
    JSR L96CC
    JSR L96CC
    JSR L96CC
    STA $1F
    JSR L96CC
    STA $20
    BCS L8F38
    LDX #.lobyte(L8F3F)
    LDY #.hibyte(L8F3F)
    JSR PRINT_STATUS_MSG
    JSR L96CC
    STA $1D
    JSR L96CC
    STA $1E
    JSR L96CC
    JSR L96CC
    LDY #$00
L8F1A:
    JSR L96CC
    STA ($1D),Y
    BCS L8F29
    INC $1D
    BNE L8F1A
    INC $1E
    BNE L8F1A
L8F29:
    BIT $C155
    BPL L8F38
    LDX $1D
    LDY $1E
    STX $8036
    STY $8037
L8F38:
    CLC

; ============================================================
; MODEM_SEND_CMD
; ============================================================
    ROR $C155
    JMP ($001F)
L8F3F:
    JMP $4E49
    .byte $4B, $49, $4E, $47, $00  ; $8F42 KING.

; --- MODEM_SEND_CMD ---
; Send command packet, handle disconnect states
MODEM_SEND_CMD:
    CPX #$00                            ; KERNAL_CLRCHN
    BEQ L8F7E
    STX $C150
    LDX $C154
    TXS
    JSR PROTO_DISPATCH_TABLE
    JSR KERNAL_CLRCHN
    JSR L8FF2
    LDA $C151
    STA VIC_BORDER
    LDY $C150
    LDX $8FAF,Y
    LDA $8FB4,Y
    TAY
    JSR PRINT_STATUS_MSG
    JSR CLEAR_STATUS
    LDA $C153
    STA $0286                           ; KERNAL_CLRCHN
    LDX #.lobyte(L8FDA)
    LDY #.hibyte(L8FDA)
    JMP PRINT_STRING
L8F7E:
    LDX $C154
    TXS                                 ; PRINT_STRING
    JSR KERNAL_CLRCHN
    LDA $8014
    STA $0286
    LDX #.lobyte(L9CF4)
    LDY #.hibyte(L9CF4)
    JSR PRINT_STRING
L8F92:
    LDA CIA1_PRB
    CMP CIA1_PRB
    BNE L8F92
    CMP #$FF
    BNE L8F92
    LDA #$00
    STA $C6
    BIT $8010
    BPL L8FAA
    JSR L96D8
L8FAA:
    JSR L8FF2
    JMP PROTO_DISPATCH_TABLE
    .byte $00, $BA, $BB, $D4, $D7, $C1, $8F, $8F, $8F, $8F, $20, $44, $49, $53, $43, $4F  ; $8FB0 .......... DISCO
    .byte $4E, $4E, $45, $43, $54, $45, $44, $20, $2D, $20, $42, $41, $44, $20, $4C, $49  ; $8FC0 NNECTED - BAD LI
    .byte $4E, $45, $3F, $00, $57, $52, $00, $52, $57, $00  ; $8FD0 NE?.WR.RW.
L8FDA:
    .byte $93  ; $8FDA .
    .byte $0E, $43, $4F, $4E, $4E, $45, $43, $54, $20, $41, $47, $41, $49, $4E, $20, $50  ; $8FDB .CONNECT AGAIN P
    .byte $4C, $45, $41, $53, $45, $0D, $00  ; $8FEB LEASE..
L8FF2:
    BIT $C155
    BPL L8FFA
    JSR L833A
L8FFA:
    RTS                                 ; KERNAL_GETIN
L8FFB:
    LDX #.lobyte(L9010)
    LDY #.hibyte(L9010)
    JSR PRINT_STATUS_MSG

; --- CLEAR_STATUS ---
; Clear the status bar
CLEAR_STATUS:
    LDA #$00
    STA $C6
    STX $19
L9008:
    JSR KERNAL_GETIN
    BEQ L9008
    LDX $19
    RTS

; ============================================================
; ============================================================
L9010:
    .byte $50  ; $9010 P
    .byte $52, $45, $53, $53, $20, $41, $4E, $59, $20, $4B, $45, $59, $00  ; $9011 RESS ANY KEY.

; --- STATUS_LINE ---
; Display status line
STATUS_LINE:
    LDX #$01                            ; INPUT_LINE
    LDY #$01
    LDA #$00
    CLC
    JSR SETUP_INPUT_PARAMS
    LDX #$00
    LDY #$02
    JSR INPUT_LINE
    BCS L903E
    LDA $0200
    AND #$DF
    CMP #$59
    BEQ L904D
    CMP #$4E
    BEQ L904D                           ; STATUS_LINE
L903E:
    LDA #$9D
    JSR KERNAL_CHROUT
    CPY #$00
    BEQ STATUS_LINE                     ; PROTOCOL_STATE_INIT
    JSR KERNAL_CHROUT
    JMP STATUS_LINE
L904D:
    CMP #$59
    RTS
L9050:
    JSR L9062
    JSR PROTOCOL_STATE_INIT
    JSR L9076
    LDA #$00
    STA $D015
    LDA #$0E
    BNE L9078
L9062:
    LDA #$93
    BNE L9078
L9066:
    LDA #$13
    BNE L9078
L906A:
    LDA #$20                            ; KERNAL_CHROUT
    BNE L9078
L906E:
    LDA #$0D
    BNE L9078
L9072:
    LDA #$12
    BNE L9078
L9076:
    LDA #$92
L9078:
    JMP KERNAL_CHROUT

; --- PRINT_STATUS_MSG ---
; Print message on status bar
PRINT_STATUS_MSG:
    STX $1B
    STY $1C
    JSR L93B4
    LDA $0286

; ============================================================
; ============================================================
    PHA
    JSR L9097
    JSR L9076                           ; PROTOCOL_STATE_INIT
    PLA
    STA $0286
    JMP L93BF

; --- CURSOR_HOME ---
; Move cursor to home position
CURSOR_HOME:
    STX $1B
    STY $1C
L9097:
    JSR PROTOCOL_STATE_INIT
    JSR L90AF
    JSR L9072
    LDA VIC_BGCOL0
    AND #$0F
    TAX
    LDA $93A4,X

; ============================================================
; PRINT_STRING
; ============================================================
    STA $0286
    JMP L90BB
L90AF:
    LDX #$18
    LDY #$00
    CLC                                 ; KERNAL_CHROUT
    JMP $FFF0

; --- PRINT_STRING ---
; Print null-terminated string (X=lo, Y=hi)
PRINT_STRING:
    STX $1B
    STY $1C
L90BB:
    LDY #$00
L90BD:
    LDA ($1B),Y                         ; workspace
    BEQ L90C7
    JSR KERNAL_CHROUT
    INY
    BNE L90BD
L90C7:
    RTS

; --- SETUP_INPUT_PARAMS ---
; Configure input line parameters
SETUP_INPUT_PARAMS:
    STX $C143
    STY $C144
    STA $C146

; ============================================================
; INPUT_LINE
; ============================================================
    TAX
    LDA #$00
    ROR
    CPX #$00
    BEQ L90DB
    ORA #$40
L90DB:
    STA $C145
    RTS

; --- INPUT_LINE ---
; Read a line of user input
INPUT_LINE:
    STX $1D
    STY $1E                             ; KERNAL_CHROUT
    LDY #$00
    STY $1A
    STY $C6
L90E9:
    LDA #$00                            ; KERNAL_GETIN
    STA $D4
    LDA #$5F
    JSR KERNAL_CHROUT
    LDA #$9D
    JSR KERNAL_CHROUT
L90F7:
    JSR KERNAL_GETIN
    BEQ L90F7
    LDY $1A
    CMP #$03
    BNE L9107
    JSR L906A
    SEC
    RTS
L9107:
    CPY $C144
    BCC L9110
    CMP #$0D
    BEQ L916C
L9110:
    CPY #$00
    BEQ L9128                           ; KERNAL_CHROUT
    CMP #$14
    BNE L9128
    JSR L906A
    LDA #$9D
    JSR KERNAL_CHROUT
    JSR KERNAL_CHROUT
    DEC $1A
    JMP L90E9
L9128:
    CPY $C143
    BEQ L90F7
    BIT $C145
    BVC L9139
    CMP $C146
    BEQ L9162
    BNE L913B
L9139:
    BPL L9145
L913B:
    CMP #$2E                            ; ;--- MODIFIED: allow . for IP
    BCC L90F7
    CMP #$3B                            ; ;--- MODIFIED: allow : for port
    BCS L90F7
    BCC L9162
L9145:
    CMP #$22
    BEQ L90F7
    CMP #$20
    BCC L90F7
    CMP #$60
    BCC L9162
    TAX
    LDA $D018
    AND #$02
    BEQ L90F7
    TXA
    CMP #$A0
    BCC L90F7
    CMP #$E0
    BCS L90F7
L9162:
    JSR KERNAL_CHROUT
    STA ($1D),Y
    INC $1A
    JMP L90E9
L916C:
    JSR L906A
    CLC
    RTS

; --- FILE_UPLOAD ---
; Upload file to server (CNSAVE)
FILE_UPLOAD:
    STA $C147
    STX $8032
    LDX #.lobyte(L9256)
    LDY #.hibyte(L9256)
    JSR PRINT_STRING
    JSR L92AD
    LDY #$00
    BCS L9186
    INY
L9186:
    LDA #$00
    LDX #$10                            ; INPUT_LINE
    CLC
    JSR SETUP_INPUT_PARAMS
    LDA $D018                           ; VIC_MEMSETUP
    PHA
    LDX #.lobyte(L801E)
    LDY #.hibyte(L801E)                            ; KERNAL_CHROUT
    JSR INPUT_LINE
    STY $19
    PLA
    STA $D018
    PHP
    LDA #$08
    JSR KERNAL_CHROUT
    PLP
    BCC L91AB
    JMP L924C
L91AB:
    BIT $C156
    BPL L91FA
    BMI L91BF

; --- FILE_DOWNLOAD ---
; Download file from server
FILE_DOWNLOAD:
    STA $C147
    STX $8032
    STY $19
    JSR L92AD
    BCC L91FA
L91BF:
    LDA $19
    LDX #.lobyte(L801E)
    LDY #.hibyte(L801E)                            ; workspace
    JSR KERNAL_SETNAM
    LDA $8032
    CMP #$50
    BEQ L91F7
    LDY #$00                            ; KERNAL_SETLFS
    LDA $C147
    CMP #$57
    BNE L91D9                           ; CURSOR_HOME
    INY
L91D9:
    LDX #$01
    LDA #$08
    JSR KERNAL_SETLFS
    LDX #.lobyte(L926D)
    LDY #.hibyte(L926D)
    JSR CURSOR_HOME
    JSR L9290
    JSR $FFC0
    JSR L92A2
    BCC L9250
    LDA #$08
    JSR $FFC3
L91F7:
    SEC
    BCS L9250
L91FA:
    LDY $19
    LDA $C147
    STA $8021,Y
    LDA $8032
    STA $801F,Y
    LDA #$2C
    STA L801E,Y
    STA $8020,Y                         ; KERNAL_SETNAM
    TYA
    CLC
    ADC #$06
    STA $C148                           ; KERNAL_SETLFS
    LDX #$1C                            ; KERNAL_OPEN
    LDY #$80
L921B:
    JSR KERNAL_SETNAM
    LDA #$08
    TAX
    TAY
    JSR KERNAL_SETLFS
    JSR $FFC0                           ; CURSOR_HOME
    JSR L92E8                           ; STATUS_LINE
    BCC L9250
    BPL L9250
    LDX #.lobyte(L9264)
    LDY #.hibyte(L9264)
    JSR CURSOR_HOME
    JSR STATUS_LINE                     ; workspace
    BNE L924C                           ; workspace
    JSR L92AD
    BCS L9250
    LDX #.lobyte(L801B)
    LDY #.hibyte(L801B)
    INC $C148
    LDA $C148
    BNE L921B
L924C:
    JSR L92E0
    SEC
L9250:
    PHP
    JSR L9076
    PLP
    RTS
L9256:
    .byte $09  ; $9256 .
    .byte $20, $46, $49, $4C, $45, $20, $4E, $41, $4D, $45, $3F, $20, $00  ; $9257  FILE NAME? .
L9264:
    .byte $52  ; $9264 R
    .byte $45, $50, $4C, $41, $43, $45, $3F, $20  ; $9265 EPLACE? 
L926D:
    .byte $00  ; $926D .
L926E:
    .byte $C9  ; $926E .
    .byte $0D, $D0, $04, $38, $66, $19, $60, $24, $19, $10, $13, $18, $66, $19, $48, $8A  ; $926F ...8f.`$....f.H.
    .byte $48, $98, $48  ; $927F H.H
    JSR PROTOCOL_STATE_INIT
    JSR L90AF
    PLA
    TAY
    PLA
    TAX
    PLA
    JMP $F1CA
L9290:
    LDX #.lobyte(L926E)
    LDY #.hibyte(L926E)
    STX $0326
    STY $0327
    CLC
    ROR $19
    LDA #$80
    JMP $FF90
L92A2:
    LDX #$CA
    LDY #$F1
    STX $0326
    STY $0327                           ; KERNAL_SETLFS
    RTS                                 ; KERNAL_OPEN
L92AD:
    LDA #$00
    JSR KERNAL_SETNAM
    LDA #$0F
    TAY
    LDX #$08                            ; workspace
    JSR KERNAL_SETLFS
    JSR $FFC0
    LDX #$0F

; ============================================================
; FRAME_STORE
; ============================================================
    JSR $FFC9
    PHP
    ROR $C156
    JSR KERNAL_CLRCHN
    PLP
    BCS L92E0
    RTS

; --- FRAME_STORE ---
; Store frame data
FRAME_STORE:
    JSR L9290
    LDA #$08
    JSR $FFC3
    BCC L92DA                           ; KERNAL_CLOSE
    JSR $FFE7
L92DA:
    JSR L92A2
    JSR L92E8
L92E0:
    PHP
    LDA #$0F
    JSR $FFC3
    PLP
    RTS
L92E8:
    JSR L935F
    PHP
    LDX #$00
    PLP
    BEQ L9306
    LDX #$A0
    CMP #$32
    BEQ L9306
    LDX #$80
    CMP #$36
    BNE L9306
    LDY $0201                           ; workspace
    CPY #$33
    BNE L9306
    LDX #$C0
L9306:
    STX $C149
    LDA #$20
    BIT $C149
    BPL L9339
    BVS L9339
    BNE L932B
    LDX #$00
L9316:
    LDA $0200,X
    INX
    CMP #$2C
    BNE L9316
L931E:
    LDA $0200,X
    INX                                 ; CURSOR_HOME
    CMP #$2C
    BNE L931E
    LDA #$00
    STA $01FF,X                         ; PRINT_STRING
L932B:
    LDX #$53                            ; workspace
    LDY #$93
    JSR CURSOR_HOME
    LDX #$00                            ; KERNAL_CLOSE
    LDY #$02
    JSR PRINT_STRING
L9339:
    ASL $C149
    BCC L9352
    LDA #$08
    JSR $FFC3                           ; workspace
    JSR L92E0
    LDA $C149
    BMI L9351
    JSR CLEAR_STATUS
    LDA $C149
L9351:
    SEC
L9352:
    RTS
L9353:
    .byte $44  ; $9353 D
    .byte $49, $53, $4B, $20, $45, $52, $52, $4F, $52, $20, $00  ; $9354 ISK ERROR .
L935F:
    BIT $C156                           ; KERNAL_GETIN
    BPL L9367
    LDA #$00
    RTS
L9367:
    LDX #$0F
    JSR $FFC6
    LDX #$00
L936E:
    JSR KERNAL_GETIN
    CMP #$0D
    BEQ L937B                           ; KERNAL_CLRCHN
    STA $0200,X
    INX
    BNE L936E
L937B:
    LDA #$00
    STA $0200,X
    STA $90
    JSR KERNAL_CLRCHN
    LDA $0200
    CMP #$30
    RTS

; --- PROTOCOL_STATE_INIT ---
; Initialize protocol state variables
PROTOCOL_STATE_INIT:
    LDA VIC_BGCOL0
    AND #$0F
    TAX
    LDA $93A4,X
    TAX
    LDY #$27
L9397:
    LDA #$A0
    STA $07C0,Y
    TXA
    STA $DBC0,Y
    DEY
    BPL L9397
    RTS
    .byte $01, $00, $01, $00, $01, $01, $01, $00, $00, $01, $00, $01, $01, $00, $01, $00  ; $93A4 ................
L93B4:
