; =================================================================
; ACIA DRIVER — SwiftLink/6551 hardware layer
; =================================================================
; Located after terminal code (at $BE03+)
; Called from ROM via JMP trampolines at MODEM_REG_WRITE/MODEM_REG_READ
;
; This replaces the original Compunet brick modem hardware layer.
; The X.25 protocol engine in ROM is unchanged — it still calls
; MODEM_REG_WRITE (X=reg, A=value) and MODEM_REG_READ (X=reg, A=result).
; We translate those register-select calls to ACIA operations.
; =================================================================

.segment "ACIA"

; --- Hardware Registers ---

; --- NMI Ring Buffer ---

; --- System Vectors ---

; =================================================================
; ACIA_INIT — Initialize ACIA and install NMI handler
; Called from MODEM_CHECK trampoline
; =================================================================
ACIA_INIT:
    ; Reset ACIA
    LDA #$00
    STA ACIA_CMD
    ; Configure: 19200 baud, 8N1, 1 stop bit
    LDA #$1F
    STA ACIA_CTRL
    ; Enable DTR + RX interrupt (NMI)
    LDA #$09
    STA ACIA_CMD
    ; Clear ring buffer
    LDA #$00
    STA NMI_BUF_TAIL
    STA NMI_BUF_HEAD
    ; Copy NMI handler to $CF00 (always-visible RAM)
    ; NMI can fire when $01=$37 (BASIC ROM at $A000-$BFFF)
    ; so the handler MUST be below $A000 or in I/O-visible RAM
    LDX #(NMI_HANDLER_END - NMI_HANDLER - 1)
@copy_nmi:
    LDA NMI_HANDLER,X
    STA $CF00,X
    DEX
    BPL @copy_nmi
    ; Install NMI vector pointing to $CF00
    SEI
    LDA #$00
    STA NMI_VECTOR
    LDA #$CF
    STA NMI_VECTOR+1
    CLI
    RTS

; =================================================================
; NMI_HANDLER — Receive interrupt handler
; Fires when ACIA receives a byte. Stores in ring buffer.
; Disables/re-enables RX IRQ around read (prevents re-entrancy).
; =================================================================
NMI_HANDLER:
    PHA
    TXA
    PHA
    LDA ACIA_STATUS                     ; Read status (acknowledges NMI)
    LDA ACIA_CMD
    ORA #$02                            ; Disable RX IRQ (bit 1)
    STA ACIA_CMD
    LDA ACIA_DATA                       ; Read received byte
    LDX NMI_BUF_TAIL
    STA NMI_BUF,X                      ; Store in ring buffer
    INC NMI_BUF_TAIL                   ; Advance tail
    LDA ACIA_CMD
    AND #$FD                            ; Re-enable RX IRQ (clear bit 1)
    STA ACIA_CMD
    PLA
    TAX
    PLA
    RTI
NMI_HANDLER_END:

; =================================================================
; ACIA_REG_WRITE — Replacement for MODEM_REG_WRITE
; Input: X = register number, A = value to write
; X=4: Transmit byte via ACIA
; Other X: ignored (mode control not needed for ACIA)
; =================================================================
ACIA_REG_WRITE:
    CPX #$04
    BNE @skip
    ; Transmit byte with delay (preserves Y)
    STA ACIA_DATA
    PHA
    TYA
    PHA
    LDY #$FF
@txdly:
    DEY
    BNE @txdly
    PLA
    TAY
    PLA
@skip:
    RTS

; =================================================================
; ACIA_REG_READ — Replacement for MODEM_REG_READ
; Input: X = register number
; Output: A = value read
; X=0: Return status (bit 7=TX rdy, bit 6=RX avail, bit 5=carrier)
; X=4: Return next byte from NMI ring buffer (non-blocking)
; X=8: Return $40 (carrier detect, bit 6 set)
; =================================================================
ACIA_REG_READ:
    CPX #$04
    BEQ @rxbyte
    CPX #$00
    BEQ @status
    ; X=8 or other: return carrier detect
    LDA #$40
    RTS

@status:
    ; Poke ACIA to trigger VICE socket poll, then check buffer
    LDA ACIA_STATUS
    LDA NMI_BUF_HEAD
    CMP NMI_BUF_TAIL
    BEQ @no_rx
    LDA #$C0                            ; Data available (bits 7+6, NOT bit 5)
    LDX #$00
    RTS
@no_rx:
    LDA #$80                            ; Empty (bit 7 only — TX ready)
    LDX #$00
    RTS

@rxbyte:
    ; Poll ACIA directly — don't rely on NMI for receive
    LDA ACIA_STATUS                     ; Triggers VICE socket check
    AND #$08                            ; RDRF?
    BEQ @empty
    LDA ACIA_DATA                       ; Read byte directly from ACIA
    LDX #$04
    RTS
@empty:
    ; Also check NMI buffer as fallback
    LDX NMI_BUF_HEAD
    CPX NMI_BUF_TAIL
    BEQ @really_empty
    LDA NMI_BUF,X
    INC NMI_BUF_HEAD
    LDX #$04
    RTS
@really_empty:
    LDA #$00
    LDX #$04
    RTS

; =================================================================
; ACIA_WAIT_READY — Replacement for MODEM_WAIT_READY
; Input: A = byte to transmit
; Transmits with delay (same interface as original)
; =================================================================
ACIA_WAIT_READY:
    STA ACIA_DATA
    PHA                                 ; Preserve A
    TYA
    PHA                                 ; Preserve Y
    LDY #$FF
@wdly:
    DEY
    BNE @wdly
    ; Re-arm NMI edge detection (VICE quirk: TX kills NMI)
    LDA #$01
    STA ACIA_CMD                        ; Disable RX IRQ
    LDA #$09
    STA ACIA_CMD                        ; Re-enable (re-arms edge)
    PLA
    TAY                                 ; Restore Y
    PLA                                 ; Restore A
    RTS

; =================================================================
; ACIA_DIAL — Hayes AT dial sequence
; Sends "ATDT" + phone number from $9FF1 (length in $9FF0) + CR
; Waits for "CONNECT" response (CR-terminated)
; Returns: C=0 success, C=1 failure
; =================================================================
ACIA_DIAL:
    ; Send "ATDT"
    LDA #'A'
    JSR ACIA_WAIT_READY
    LDA #'T'
    JSR ACIA_WAIT_READY
    LDA #'D'
    JSR ACIA_WAIT_READY
    LDA #'T'
    JSR ACIA_WAIT_READY
    ; Send phone number digits
    LDY #$00
@send_digit:
    CPY $9FF0
    BEQ @send_cr
    CPY #$14                            ; Safety: max 20 chars
    BEQ @send_cr
    LDA $9FF1,Y
    CMP #$2D                            ; '-' = pause
    BNE @not_pause
    LDA #','                            ; Hayes pause
@not_pause:
    JSR ACIA_WAIT_READY
    INY
    BNE @send_digit
@send_cr:
    LDA #$0D
    JSR ACIA_WAIT_READY
    ; Re-arm NMI edge detection after TX burst
    LDA #$01
    STA ACIA_CMD                        ; Disable RX IRQ
    LDA #$09
    STA ACIA_CMD                        ; Re-enable (re-arms NMI edge)
    ; Wait for "CONNECT" response — poll for CR
@wait_resp:
    LDA ACIA_STATUS                     ; Poke VICE to check socket
    LDA NMI_BUF_HEAD
    CMP NMI_BUF_TAIL
    BEQ @wait_resp
    TAX
    LDA NMI_BUF,X
    INC NMI_BUF_HEAD
    CMP #$0D                            ; CR = end of response
    BNE @wait_resp
    ; Flush remaining buffer
    LDA NMI_BUF_TAIL
    STA NMI_BUF_HEAD
    CLC                                 ; C=0 = success
    RTS

; =================================================================
; End of ACIA driver
; =================================================================

; --- BASIC_MEM_FIX ---
; Set BASIC memory pointers so variables work below $8000
BASIC_MEM_FIX:
    LDA #$00
    STA $37                             ; Top of memory lo = $8000
    STA $33                             ; Top of strings lo = $8000
    LDA #$80
    STA $38                             ; Top of memory hi
    STA $34                             ; Top of strings hi
    ; Reset string/array pointers to match
    LDA $2D
    STA $2F                             ; Start of arrays = end of variables
    STA $31                             ; End of arrays
    LDA $2E
    STA $30
    STA $32
    RTS

; =================================================================
; ACIA_PROTO_CONNECT — Polling-based connection handshake
; =================================================================
; Replaces the original IRQ-driven PROTO_CONNECT.
; Pure polling like CCGMS — no IRQ, no CIA timer, no deadlocks.
;
; Flow:
;   1. Print "CONNECTING..."
;   2. Poll for 12 handshake bytes ($20) from server
;   3. Send CNET identification (29 bytes from $8052)
;   4. Poll for "*CON\r" response
;   5. Return C=0 success, C=1 failure
; =================================================================
ACIA_PROTO_CONNECT:
    ; Set purple border (visual indicator)
    LDA $8012
    STA $D020
    ; Print "CONNECTING..."
    LDX #.lobyte(L9E59)
    LDY #.hibyte(L9E59)
    JSR PRINT_STRING

    ; --- Step 1: Wait for handshake bytes from server ---
    ; Server sends 12 x $20 after connection. Poll until we get at least one.
    LDX #$00                            ; Timeout counter hi
    LDY #$00                            ; Timeout counter lo
@wait_handshake:
    LDA ACIA_STATUS                     ; Poke VICE to check socket
    AND #$08                            ; RDRF?
    BNE @got_handshake
    ; Check NMI buffer too
    LDA NMI_BUF_HEAD
    CMP NMI_BUF_TAIL
    BNE @got_handshake_buf
    ; Timeout check
    INY
    BNE @wait_handshake
    INX
    CPX #$FF                            ; ~16 seconds timeout
    BCC @wait_handshake
    SEC                                 ; Timeout — failure
    RTS

@got_handshake:
    LDA ACIA_DATA                       ; Read and discard handshake byte
    JMP @drain_handshake
@got_handshake_buf:
    INC NMI_BUF_HEAD                    ; Discard from buffer
@drain_handshake:
    ; Drain remaining handshake bytes (brief pause then flush)
    LDY #$00
@drain_loop:
    LDA ACIA_STATUS
    AND #$08
    BEQ @check_buf_drain
    LDA ACIA_DATA                       ; Discard
    JMP @drain_loop
@check_buf_drain:
    LDA NMI_BUF_HEAD
    CMP NMI_BUF_TAIL
    BEQ @drain_pause
    INC NMI_BUF_HEAD
    JMP @drain_loop
@drain_pause:
    ; Brief delay to let remaining bytes arrive
    INY
    BNE @drain_loop
    ; Final flush
    LDA NMI_BUF_TAIL
    STA NMI_BUF_HEAD

    ; --- Step 2: Send CNET identification ---
    LDY #$00
@send_ident:
    CPY $8051                           ; Length of identification
    BEQ @ident_done
    LDA $8052,Y                         ; Load identification byte
    JSR ACIA_WAIT_READY                 ; Transmit
    INY
    BNE @send_ident
@ident_done:

    ; --- Step 3: Wait for *CON response ---
    ; Server sends "*CON\r" — we look for the CR after receiving "*CON"
    LDX #$00                            ; Match index
    LDY #$00                            ; Timeout hi
@wait_con:
    LDA ACIA_STATUS                     ; Poke VICE
    AND #$08
    BNE @got_con_byte
    LDA NMI_BUF_HEAD
    CMP NMI_BUF_TAIL
    BNE @got_con_buf
    ; Timeout
    INY
    BNE @wait_con
    INX
    CPX #$FF
    BCC @wait_con
    SEC                                 ; Timeout — failure
    RTS

@got_con_byte:
    LDA ACIA_DATA
    JMP @check_con
@got_con_buf:
    LDX NMI_BUF_HEAD
    LDA NMI_BUF,X
    INC NMI_BUF_HEAD
@check_con:
    ; Check for CR (end of *CON\r response)
    CMP #$0D
    BEQ @con_received
    ; Reset timeout
    LDY #$00
    LDX #$00
    JMP @wait_con

@con_received:
    ; Success! Flush buffer and return
    LDA NMI_BUF_TAIL
    STA NMI_BUF_HEAD
    ; Set protocol connected flag (without installing IRQ handler)
    LDA #$80
    STA $8038                           ; Protocol state = connected
    CLC                                 ; C=0 = success
    RTS

; =================================================================
; ACIA_SEND_PACKET — Direct X.25 packet send via ACIA
; =================================================================
; Input: $C14D = payload length, $8034 = token, $C100 = payload
; Sends: $01 [total_len] [token] [seq] [payload...] [CRC_hi] [CRC_lo] $02
; Applies byte stuffing for $01/$02/$03 in data.
; Uses standard CRC-CCITT (poly $1021, init $0000).
; =================================================================
ACIA_SEND_PACKET:
    ; --- Send start marker ---
    LDA #$01
    JSR ACIA_WAIT_READY

    ; --- Calculate total length (payload + 4 header/CRC bytes) ---
    LDA $C14D
    CLC
    ADC #$04                            ; +4 for length, token, seq, (CRC counted separately? No - length = total between markers)
    ; Actually: length byte = total bytes between $01 and $02 (inclusive of length itself)
    ; Format: $01 [len] [token] [seq] [payload...] [CRC_hi] [CRC_lo] $02
    ; len = 2 (token+seq) + payload_len + 2 (CRC) + 1 (len itself)... 
    ; From PROTOCOL.md: length = total bytes between markers
    ; So len = 1(len) + 1(token) + 1(seq) + payload + 2(CRC) = payload + 5
    LDA $C14D
    CLC
    ADC #$05
    STA $C14E                           ; Total length byte

    ; --- Init CRC ---
    LDA #$00
    STA $C21D                           ; CRC hi
    STA $C21E                           ; CRC lo

    ; --- Send length (with stuffing + CRC) ---
    LDA $C14E
    JSR @send_stuffed_crc

    ; --- Send token (with stuffing + CRC) ---
    LDA $8034
    JSR @send_stuffed_crc

    ; --- Send sequence (with stuffing + CRC) ---
    LDA $C20E                           ; TX sequence number
    JSR @send_stuffed_crc

    ; --- Send payload bytes (with stuffing + CRC) ---
    LDY #$00
@send_payload:
    CPY $C14D
    BEQ @send_crc
    LDA $C100,Y
    JSR @send_stuffed_crc
    INY
    BNE @send_payload

@send_crc:
    ; --- Send CRC hi (with stuffing) ---
    LDA $C21D
    JSR @send_stuffed
    ; --- Send CRC lo (with stuffing) ---
    LDA $C21E
    JSR @send_stuffed

    ; --- Send end marker ---
    LDA #$02
    JSR ACIA_WAIT_READY

    ; --- Advance sequence number ---
    LDX $C20E
    INX
    CPX #$60
    BNE @seq_ok
    LDX #$20
@seq_ok:
    STX $C20E

    RTS

; --- Send byte with stuffing + update CRC ---
@send_stuffed_crc:
    PHA
    JSR @update_crc                     ; Update CRC with byte in A (on stack)
    PLA
    ; Fall through to send_stuffed

; --- Send byte with byte stuffing ---
@send_stuffed:
    CMP #$01
    BEQ @stuff_01
    CMP #$02
    BEQ @stuff_02
    CMP #$03
    BEQ @stuff_03
    JMP ACIA_WAIT_READY                 ; Normal byte — just send

@stuff_01:
    LDA #$03
    JSR ACIA_WAIT_READY
    LDA #$21
    JMP ACIA_WAIT_READY
@stuff_02:
    LDA #$03
    JSR ACIA_WAIT_READY
    LDA #$22
    JMP ACIA_WAIT_READY
@stuff_03:
    LDA #$03
    JSR ACIA_WAIT_READY
    LDA #$23
    JMP ACIA_WAIT_READY

; --- Update CRC-CCITT with byte (byte on stack, accessed via TSX) ---
@update_crc:
    ; Standard CRC-CCITT: poly $1021, MSB-first
    ; CRC state in $C21D (hi) / $C21E (lo)
    ; Input byte from stack (caller did PHA before JSR)
    TSX
    LDA $0103,X                         ; Get the byte from stack (PHA byte is 3 above SP)
    EOR $C21D                           ; XOR with CRC hi
    STA $C21D
    LDX #$08                            ; 8 bits
@crc_loop:
    ASL $C21E
    ROL $C21D
    BCC @crc_no_xor
    LDA $C21D
    EOR #$10
    STA $C21D
    LDA $C21E
    EOR #$21
    STA $C21E
@crc_no_xor:
    DEX
    BNE @crc_loop
    RTS
